import{_ as a,o,c as d,a0 as t}from"./chunks/framework.BFy5Ffxw.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),i={name:"changelog.md"};function r(n,e,l,s,c,h){return o(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to cymbal are documented here.</p><h2 id="_0-9-1-2026-04-11" tabindex="-1">[0.9.1] - 2026-04-11 <a class="header-anchor" href="#_0-9-1-2026-04-11" aria-label="Permalink to &quot;[0.9.1] - 2026-04-11&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>C/C++ call-site reference extraction</strong> — <code>refs</code>, <code>trace</code>, <code>impact</code>, and <code>investigate</code> now return call-graph data for C and C++ files. Includes normalization for dot, arrow (<code>-&gt;</code>), and scope-resolution (<code>::</code>) separators, plus C++ template call stripping (<code>std::max&lt;int&gt;</code> → <code>max</code>) (PR #12, @Phototonic).</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Library usage guide</strong> — added <code>docs/library.md</code> and a README section covering how to import cymbal as a Go library.</li><li><strong>Test helper dedup</strong> — extracted shared <code>debugParseResult</code> helper from duplicated closures in C/C++ feature tests.</li></ul><h2 id="_0-9-0-2026-04-09" tabindex="-1">[0.9.0] - 2026-04-09 <a class="header-anchor" href="#_0-9-0-2026-04-09" aria-label="Permalink to &quot;[0.9.0] - 2026-04-09&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Library-ready package layout</strong> — moved all four <code>internal/</code> packages to top-level importable packages: <code>symbols/</code>, <code>parser/</code>, <code>index/</code>, <code>walker/</code>. External Go projects can now import cymbal as a library (e.g., <code>import &quot;github.com/1broseidon/cymbal/index&quot;</code>). The CLI (<code>cmd/</code>) continues to work unchanged. This is a <strong>breaking change</strong> for any code that imported <code>internal/</code> paths directly (which was not possible for external consumers, but affects forks).</li></ul><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>MIT license file</strong>.</li><li><strong>README badges</strong> — GitHub stars, Go Reference, Go Report Card, latest release.</li></ul><h2 id="_0-8-8-2026-04-08" tabindex="-1">[0.8.8] - 2026-04-08 <a class="header-anchor" href="#_0-8-8-2026-04-08" aria-label="Permalink to &quot;[0.8.8] - 2026-04-08&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Multi-language benchmark corpus and regression detection</strong> for the bench harness.</li></ul><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li><strong>Deprecated unused LLM summarization feature</strong> — removed <code>--summarize</code>, <code>--backend</code>, and <code>--model</code> flags from <code>cymbal index</code>. The feature was underdeveloped (summaries only surfaced in <code>outline</code>, not in <code>search</code>, <code>investigate</code>, or other commands) and added significant indexing latency for minimal value. Removed upstream dependency on <code>oneagent</code>.</li></ul><h2 id="_0-8-7-2026-04-07" tabindex="-1">[0.8.7] - 2026-04-07 <a class="header-anchor" href="#_0-8-7-2026-04-07" aria-label="Permalink to &quot;[0.8.7] - 2026-04-07&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Salesforce Apex language support</strong> — classes, methods, fields, constructors, interfaces, and enums via <code>classifyJavaLike</code> reuse (PR #6, @lynxbat).</li><li><strong>Dart language support</strong> — classes, enums, mixins, extensions, type aliases, functions, methods, getters, setters, constructors, imports, and refs (PR #11, @Phototonic).</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>investigate member bleed across files</strong> — <code>investigate</code> no longer mixes members from different symbols that share the same parent name across files or languages. Member lookup is now scoped to the resolved symbol&#39;s file. Fixes #9.</li></ul><h2 id="_0-8-6-2026-04-06" tabindex="-1">[0.8.6] - 2026-04-06 <a class="header-anchor" href="#_0-8-6-2026-04-06" aria-label="Permalink to &quot;[0.8.6] - 2026-04-06&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Elixir language support</strong> — modules (<code>defmodule</code>), functions (<code>def</code>/<code>defp</code>), macros (<code>defmacro</code>), protocols (<code>defprotocol</code>), imports (<code>alias</code>/<code>import</code>/<code>use</code>/<code>require</code>), and cross-module refs.</li><li><strong>HCL/Terraform language support</strong> — resources, variables, outputs, data sources, modules, providers, and locals blocks with synthesized names (e.g., <code>aws_instance.web</code>).</li><li><strong>Protobuf language support</strong> — messages, enums, services, RPCs, and proto imports.</li><li><strong>Kotlin language support</strong> — proper symbol extraction for classes, interfaces, objects, enums, methods, and companion objects (merged PR #7).</li><li><strong>CI workflows</strong> — build, lint, test, security (<code>govulncheck</code>), and dependency review checks on PRs and main branch.</li><li><strong>PR template</strong> — required structure with summary, testing checklist, security notes, and rollout risk.</li><li><strong>PR body validation</strong> — CI check that enforces template usage and completed checklist items on non-draft PRs.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Go version</strong> — bumped from 1.25.7 to 1.25.8 to resolve stdlib vulnerability flagged by new security check.</li><li><strong>Makefile</strong> — added <code>build-check</code>, <code>vulncheck</code>, and <code>ci</code> targets.</li></ul><h2 id="_0-8-5-2026-04-05" tabindex="-1">[0.8.5] - 2026-04-05 <a class="header-anchor" href="#_0-8-5-2026-04-05" aria-label="Permalink to &quot;[0.8.5] - 2026-04-05&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Smart truncation for type symbols</strong> — <code>show</code> and <code>investigate</code> now cap class/struct/interface/enum output at 60 lines instead of dumping the entire body (e.g., FastAPI class went from 170KB to 1.8KB). Full source remains available via <code>cymbal show file:L1-L2</code>. Members are listed separately in <code>investigate</code>.</li><li><strong>Truncated member signatures</strong> — multi-line signatures in <code>investigate</code> member listings are collapsed to the first line, preventing huge docstring-heavy parameter lists from bloating output.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>README accuracy</strong> — removed unsupported languages (HCL, Dockerfile, TOML, HTML, CSS) from supported list, corrected benchmark numbers to match actual RESULTS.md, fixed &quot;Go, Python, and TypeScript&quot; to &quot;Go and Python&quot; (no TS corpus repo).</li><li><strong>Benchmark token efficiency</strong> — <code>show</code> and <code>investigate</code> for large types now dramatically outperform ripgrep instead of losing badly (FastAPI show: -1413% → 84% savings; APIRouter agent workflow: -248% → 95% savings).</li></ul><h2 id="_0-8-4-2026-04-04" tabindex="-1">[0.8.4] - 2026-04-04 <a class="header-anchor" href="#_0-8-4-2026-04-04" aria-label="Permalink to &quot;[0.8.4] - 2026-04-04&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Auto-index on first query</strong> — no more manual <code>cymbal index .</code> step. The first command in a repo automatically builds the index, with a progress indicator for large repos. Subsequent queries continue to refresh incrementally. Closes #3. (@Ismael)</li><li><strong>Git worktree support</strong> — <code>FindGitRoot</code> now detects <code>.git</code> files (used by worktrees) in addition to <code>.git</code> directories, so all commands work correctly inside <code>git worktree</code> checkouts.</li><li><strong>Intel Mac builds</strong> — release pipeline now produces <code>darwin_amd64</code> binaries and the Homebrew formula includes Intel Mac support. Closes #4. (@alec-pinson)</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Correct index path documentation</strong> — README now documents the actual OS cache directory paths (<code>~/.cache/cymbal/</code> on Linux, <code>~/Library/Caches/cymbal/</code> on macOS, <code>%LOCALAPPDATA%\\cymbal\\</code> on Windows) instead of the stale <code>~/.cymbal/</code> reference. Closes #5. (@candiesdoodle)</li><li><strong>Proper error propagation</strong> — commands no longer call <code>os.Exit(1)</code> on &quot;not found&quot; or &quot;ambiguous&quot; results. Errors now flow through cobra&#39;s error handling for consistent <code>Error:</code> prefixed output and proper exit codes.</li><li><strong>Non-git-repo warning</strong> — running cymbal outside a git repository now prints a clear warning (<code>not inside a git repository — results may be empty</code>) instead of silently returning empty results.</li></ul><h2 id="_0-8-3-2026-04-02" tabindex="-1">[0.8.3] - 2026-04-02 <a class="header-anchor" href="#_0-8-3-2026-04-02" aria-label="Permalink to &quot;[0.8.3] - 2026-04-02&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>GHCR container</strong> — pre-built multi-arch Docker image (linux/amd64, linux/arm64) published to <code>ghcr.io/1broseidon/cymbal</code> on every release, tagged with version and <code>latest</code>.</li></ul><h2 id="_0-8-2-2026-04-02" tabindex="-1">[0.8.2] - 2026-04-02 <a class="header-anchor" href="#_0-8-2-2026-04-02" aria-label="Permalink to &quot;[0.8.2] - 2026-04-02&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Docker support</strong> — Dockerfile, docker-compose.yml, and <code>CYMBAL_DB</code> environment variable for running cymbal from a container with no local Go/CGO setup. Index stored at <code>.cymbal/index.db</code> in the repo root. (@VertigoOne1)</li><li>PowerShell uninstall script (<code>uninstall.ps1</code>) with optional <code>-Purge</code> flag to remove index data. (@VertigoOne1)</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Windows binary no longer requires MinGW DLLs (<code>libgcc_s_seh-1.dll</code>, <code>libstdc++-6.dll</code>). Release workflow now statically links the C runtime on Windows. Fixes #1.</li><li>Quoted <code>$(pwd)</code> in all Docker documentation examples to handle paths with spaces.</li></ul><h2 id="_0-8-1-2026-03-27" tabindex="-1">[0.8.1] - 2026-03-27 <a class="header-anchor" href="#_0-8-1-2026-03-27" aria-label="Permalink to &quot;[0.8.1] - 2026-03-27&quot;">​</a></h2><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>cymbal structure</code> &quot;Try&quot; suggestions now deduplicated by symbol name — no more repeated suggestions when the same symbol appears in multiple files.</li></ul><h2 id="_0-8-0-2026-03-27" tabindex="-1">[0.8.0] - 2026-03-27 <a class="header-anchor" href="#_0-8-0-2026-03-27" aria-label="Permalink to &quot;[0.8.0] - 2026-03-27&quot;">​</a></h2><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>cymbal structure</code></strong> — structural overview of an indexed codebase. Shows entry points, most-referenced symbols (by call-site count), largest packages, and most-imported files. All derived from existing index data — no AI, no guessing. Answers &quot;I&#39;ve never seen this repo, where do I start?&quot; Supports <code>--json</code>.</li><li><strong>Batch mode</strong> for symbol commands — <code>investigate</code>, <code>show</code>, <code>refs</code>, <code>context</code>, and <code>impact</code> now accept multiple symbols: <code>cymbal investigate Foo Bar Baz</code>. One invocation, one JIT freshness check, multiple results. Reduces agent round-trips.</li><li><strong>Benchmark harness v2</strong> — <code>go run ./bench run</code> now measures speed, accuracy (37/37 ground-truth checks), token efficiency vs ripgrep, JIT freshness overhead, and agent workflow savings across gin, kubectl, and fastapi.</li></ul><h2 id="_0-7-3-2026-03-27" tabindex="-1">[0.7.3] - 2026-03-27 <a class="header-anchor" href="#_0-7-3-2026-03-27" aria-label="Permalink to &quot;[0.7.3] - 2026-03-27&quot;">​</a></h2><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>JIT freshness</strong> — every query command (search, show, investigate, refs, importers, impact, trace, context, outline, diff, ls --stats) now automatically checks for changed files and reindexes them before returning results. No manual <code>cymbal index</code> needed between edits. The index is always correct. <ul><li>Hot path (nothing changed): ~2ms overhead on small repos, ~14ms on 3000-file repos</li><li>Dirty path (files edited): only changed files are reparsed — 5 touched files on a 770-file repo adds ~40ms</li><li>Deleted files are automatically pruned from the index</li><li>No watch daemons, no hooks, no flags — it just works</li></ul></li><li><code>index.EnsureFresh(dbPath)</code> public API for programmatic use.</li></ul><h2 id="_0-7-2-2026-03-26" tabindex="-1">[0.7.2] - 2026-03-26 <a class="header-anchor" href="#_0-7-2-2026-03-26" aria-label="Permalink to &quot;[0.7.2] - 2026-03-26&quot;">​</a></h2><h3 id="added-10" tabindex="-1">Added <a class="header-anchor" href="#added-10" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>PowerShell install script for Windows (<code>install.ps1</code>) — <code>irm .../install.ps1 | iex</code> fetches the latest release, extracts to <code>%LOCALAPPDATA%\\cymbal</code>, and adds to PATH.</li></ul><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Database file created inside the project directory on Windows when <code>%USERPROFILE%</code> is unset. Now uses <code>os.UserCacheDir()</code> (<code>%LOCALAPPDATA%</code> on Windows) as the primary data directory, with safe fallbacks that never produce a relative path.</li></ul><h2 id="_0-7-1-2026-03-26" tabindex="-1">[0.7.1] - 2026-03-26 <a class="header-anchor" href="#_0-7-1-2026-03-26" aria-label="Permalink to &quot;[0.7.1] - 2026-03-26&quot;">​</a></h2><h3 id="added-11" tabindex="-1">Added <a class="header-anchor" href="#added-11" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Windows (amd64) binary in release pipeline — builds with Cgo on <code>windows-latest</code>, packaged as <code>.zip</code>.</li></ul><h2 id="_0-7-0-2026-03-25" tabindex="-1">[0.7.0] - 2026-03-25 <a class="header-anchor" href="#_0-7-0-2026-03-25" aria-label="Permalink to &quot;[0.7.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-12" tabindex="-1">Added <a class="header-anchor" href="#added-12" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Flexible symbol resolution pipeline (<code>flexResolve</code>) — shared by <code>show</code>, <code>investigate</code>, and <code>context</code>: <ul><li><strong>Ambiguity auto-resolve</strong>: picks best match by path proximity and kind priority, notes alternatives in frontmatter (<code>matches: 2 (also: path:line)</code>)</li><li><strong>Dot-qualified names</strong>: <code>config.Load</code> resolves by filtering parent/path. Works for <code>pkg.Function</code> and <code>Class.method</code> patterns.</li><li><strong>Fuzzy fallback</strong>: exact → case-insensitive (<code>COLLATE NOCASE</code>) → FTS prefix match. Marks results with <code>fuzzy: true</code>.</li></ul></li><li><code>SearchSymbolsCI</code> store method for case-insensitive exact name match.</li><li><code>InvestigateResolved</code> for investigating pre-resolved symbols.</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>show</code> and <code>investigate</code> no longer error on ambiguous symbols — they auto-resolve and return the best match with disambiguation hints in frontmatter.</li></ul><h2 id="_0-6-0-2026-03-25" tabindex="-1">[0.6.0] - 2026-03-25 <a class="header-anchor" href="#_0-6-0-2026-03-25" aria-label="Permalink to &quot;[0.6.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-13" tabindex="-1">Added <a class="header-anchor" href="#added-13" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>cymbal trace &lt;symbol&gt;</code> — downward call graph traversal. Follows what a symbol calls, what those call, etc. (BFS, depth 3 default, max 5). Filters stdlib noise to surface project-defined symbols. Complementary to <code>impact</code> (upward) and <code>investigate</code> (adaptive).</li></ul><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Agent integration guide (README, CLAUDE.md, AGENTS.md) restructured around three core commands: <code>investigate</code> (understand), <code>trace</code> (downward), <code>impact</code> (upward). Based on real-world observation of an agent making 22 sequential calls that trace + investigate handled in 4.</li></ul><h2 id="_0-5-1-2026-03-25" tabindex="-1">[0.5.1] - 2026-03-25 <a class="header-anchor" href="#_0-5-1-2026-03-25" aria-label="Permalink to &quot;[0.5.1] - 2026-03-25&quot;">​</a></h2><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>show</code> and <code>investigate</code> now accept <code>file:Symbol</code> syntax to disambiguate when multiple symbols share a name (e.g., <code>cymbal show config.go:Config</code>, <code>cymbal investigate internal/config/config.go:Config</code>).</li><li><code>show</code> line range parser accepts <code>L</code>-prefixed ranges (<code>file.go:L119-L132</code>) — was advertised in README but broken.</li></ul><h2 id="_0-5-0-2026-03-25" tabindex="-1">[0.5.0] - 2026-03-25 <a class="header-anchor" href="#_0-5-0-2026-03-25" aria-label="Permalink to &quot;[0.5.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-14" tabindex="-1">Added <a class="header-anchor" href="#added-14" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>cymbal investigate &lt;symbol&gt;</code> — kind-adaptive symbol exploration. Returns the right shape of information based on what a symbol is: functions get source + callers + shallow impact; types get source + members + references; ambiguous names get ranked candidates. Eliminates the agent&#39;s decision loop of choosing between search/show/refs/impact.</li><li><code>ChildSymbols</code> store method for querying methods/fields by parent type name.</li><li>Benchmark suite now tracks output size (bytes + approximate tokens) and includes ripgrep refs/show equivalents for fair token efficiency comparison.</li></ul><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>TypeScript/JavaScript <code>export</code> statement dedup — exported functions, classes, interfaces, types, and enums no longer appear twice in the index (same pattern as the Python decorator fix in v0.4.1).</li></ul><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>README rewritten with workflow-centric agent integration guide. <code>investigate</code> is the recommended default, specific commands are escape hatches.</li></ul><h2 id="_0-4-1-2026-03-24" tabindex="-1">[0.4.1] - 2026-03-24 <a class="header-anchor" href="#_0-4-1-2026-03-24" aria-label="Permalink to &quot;[0.4.1] - 2026-03-24&quot;">​</a></h2><h3 id="added-15" tabindex="-1">Added <a class="header-anchor" href="#added-15" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Benchmark suite now tracks output size (bytes + approximate tokens) per query, comparing token efficiency across tools. Ripgrep refs and show equivalents added for fair comparison.</li></ul><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Python decorated functions and classes no longer appear twice in outline/search/show. Tree-sitter&#39;s <code>decorated_definition</code> wrapper was causing double emission — inner <code>function_definition</code>/<code>class_definition</code> nodes are now skipped when their parent already emitted them.</li></ul><h2 id="_0-4-0-2026-03-24" tabindex="-1">[0.4.0] - 2026-03-24 <a class="header-anchor" href="#_0-4-0-2026-03-24" aria-label="Permalink to &quot;[0.4.0] - 2026-03-24&quot;">​</a></h2><h3 id="changed-7" tabindex="-1">Changed <a class="header-anchor" href="#changed-7" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Indexing 2x faster</strong> — separated parse workers (parallel, CPU-bound) from serial writer with batched transactions, eliminating goroutine contention on SQLite&#39;s writer lock. Cold index dropped from 2.4s to 1.05s on cli/cli (729 files).</li><li><strong>Reindex 4x faster</strong> — mtime_ns + file size skip check with pre-loaded map avoids reading files or querying DB per-file. Reindex dropped from 57ms to 14ms on cli/cli.</li><li><strong>Prepared statement reuse</strong> — statements prepared once per batch (5 per batch vs 5 per file), reducing cgo overhead on large repos.</li><li><strong>Read-once parse+hash</strong> — workers read each file once and pass bytes to both parser and hasher, eliminating duplicate I/O.</li><li><strong>Row-based batch flushing</strong> — flush at 100 files OR 50k rows (symbols+imports+refs), preventing pathological batches from symbol-dense repos.</li><li><strong>Robust change detection</strong> — mtime stored as nanosecond integer + file size; skip only when both match exactly. Catches coarse FS timestamps and tools that preserve mtime.</li><li><strong>Walker language filtering</strong> — unsupported languages (.json, .md, .toml) filtered before stat, reducing channel traffic and allocations.</li></ul><h3 id="added-16" tabindex="-1">Added <a class="header-anchor" href="#added-16" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Benchmark suite (<code>bench/</code>) comparing cymbal vs ripgrep vs ctags across Go, Python, and TypeScript repos with reproducible pinned corpus.</li><li>Progress indicator on stderr after 10s for large repos (e.g., kubernetes at 16k files).</li><li><code>ParseBytes</code> function for parsing from pre-read byte slices.</li></ul><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Stale file pruning</strong> — deleted/renamed files are removed from the index on reindex by diffing walker paths against stored paths.</li><li><strong>Savepoint-per-file in batch writer</strong> — a single file write failure no longer corrupts the entire batch; partial data is rolled back cleanly.</li><li><strong>Accurate stats after commit</strong> — indexed/found counts published only after successful tx.Commit(), preventing inflation on commit failure.</li><li><strong>Split error types</strong> — skip reasons separated into unchanged, unsupported, parse_error, write_error; CLI shows non-zero counts conditionally.</li></ul><h2 id="_0-3-0-2026-03-24" tabindex="-1">[0.3.0] - 2026-03-24 <a class="header-anchor" href="#_0-3-0-2026-03-24" aria-label="Permalink to &quot;[0.3.0] - 2026-03-24&quot;">​</a></h2><h3 id="changed-8" tabindex="-1">Changed <a class="header-anchor" href="#changed-8" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Per-repo databases</strong> — each repo gets its own SQLite DB at <code>~/.cymbal/repos/&lt;hash&gt;/index.db</code>, eliminating cross-repo symbol bleed. Searching in repo A no longer returns results from repo B.</li><li>Removed <code>repos</code> table and <code>repo_id</code> column — no longer needed since each DB is one repo</li><li>Added <code>meta</code> table storing <code>repo_root</code> path per database</li><li><code>cymbal ls --repos</code> lists all indexed repos with file/symbol counts</li><li><code>--repo</code> flag removed (repo identity comes from DB path now)</li><li><code>--db</code> flag still works as override for all commands</li></ul><h3 id="added-17" tabindex="-1">Added <a class="header-anchor" href="#added-17" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>refs</code> and <code>impact</code> now show surrounding call-site context (1 line above/below by default, adjustable with <code>-C</code>)</li><li>VitePress docs site at chain.sh/cymbal with chain.sh design language</li></ul><h3 id="fixed-10" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-10" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Stale symbol entries from moved/deleted repos no longer pollute search results</li></ul><h2 id="_0-2-0-2026-03-23" tabindex="-1">[0.2.0] - 2026-03-23 <a class="header-anchor" href="#_0-2-0-2026-03-23" aria-label="Permalink to &quot;[0.2.0] - 2026-03-23&quot;">​</a></h2><h3 id="changed-9" tabindex="-1">Changed <a class="header-anchor" href="#changed-9" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>All commands now output agent-native frontmatter+content format by default (YAML metadata + content body, optimized for LLM token efficiency)</li><li><code>refs</code> and <code>impact</code> deduplicate identical call sites — grouped by file with site count</li><li><code>context</code> callers section uses the same dedup</li><li><code>search</code> results ranked by relevance: exact name match first, then prefix, then contains</li><li>Default limits lowered: refs 50→20, impact 100→50, search 50→20</li><li><code>refs</code>, <code>impact</code>, and <code>context</code> now show actual source lines at call sites, not just line numbers</li></ul><h2 id="_0-1-0-2026-03-23" tabindex="-1">[0.1.0] - 2026-03-23 <a class="header-anchor" href="#_0-1-0-2026-03-23" aria-label="Permalink to &quot;[0.1.0] - 2026-03-23&quot;">​</a></h2><h3 id="added-18" tabindex="-1">Added <a class="header-anchor" href="#added-18" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Core indexing engine with tree-sitter parsing, SQLite FTS5 storage, and AI summaries via oneagent</li><li>Batched summarization with diff tracking and model selection</li><li><code>cymbal index</code> — index a codebase</li><li><code>cymbal ls</code> — list files and repo stats</li><li><code>cymbal outline</code> — show file structure</li><li><code>cymbal search</code> — symbol and text search</li><li><code>cymbal show</code> — display symbol source</li><li><code>cymbal refs</code> — find references to a symbol</li><li><code>cymbal importers</code> — reverse import lookup</li><li><code>cymbal impact</code> — transitive caller analysis</li><li><code>cymbal diff</code> — git diff scoped to a symbol</li><li><code>cymbal context</code> — bundled source, callers, and imports in one call</li></ul><h3 id="fixed-11" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-11" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Overlapping sub-repo detection prevents duplicate symbol indexing</li></ul>',109)])])}const g=a(i,[["render",r]]);export{m as __pageData,g as default};
